   370→      pauseTimer: () => {
   371→        const { activeEntry } = get();
   372→        if (!activeEntry) return;
   373→
   374→        const now = new Date().toISOString();
   375→        const pausedEntry = {
   376→          ...activeEntry,
   377→          pausedAt: now,
   378→          isPaused: true,
