   384→      },
   385→
   386→      resumeTimer: () => {
   387→        const { activeEntry } = get();
   388→        if (!activeEntry || !activeEntry.isPaused) return;
   389→
   390→        const now = new Date().toISOString();
   391→        const pausedDuration = activeEntry.pausedAt
