   622→      loadEntries: async (filters) => {
   623→        let startDate: Date | undefined;
   624→        let endDate: Date | undefined;
   625→
   626→        // Calculate date range based on filter
   627→        if (filters?.dateRange) {
   628→          const now = new Date();
   629→          switch (filters.dateRange) {
   630→            case 'today':
   631→              startDate = new Date(now.setHours(0, 0, 0, 0));
   632→              endDate = new Date(now.setHours(23, 59, 59, 999));
