   657→        // OPTIMIZATION: Use database-level filtering with smart limits
   658→        // For small date ranges (today, yesterday), load all entries
   659→        // For large date ranges (30 days, custom), paginate with initial limit
   660→        const isSmallRange = filters?.dateRange === 'today' || filters?.dateRange === 'yesterday';
   661→        const limit = isSmallRange ? undefined : 500; // Load 500 entries max initially
   662→
   663→        const entries = await timeTrackingDb.getEntries({
   664→          startDate,
