  removeDependency: (taskId: string, dependencyId: string) => void;
  getBlockers: (taskId: string) => Task[];
  getBlocked: (taskId: string) => Task[];
  getOverdueBlockers: (taskId: string) => Task[]; // P1: Dependency Warnings

